"// Serve Page Builder static files and index
app.use('/page-builder', express.static(path.join(__dirname, '..', 'page-builder')));
app.get('/page-builder', (req, res) => {
  res.redirect('/page-builder/');
});
app.get('/page-builder{/*path}', (_req, res) => {
  res.sendFile(path.join(__dirname, '..', 'page-builder', 'index.html'));
});"

